 * @returns {boolean}
 */
function problemHasTags(problem, tags) {
  if (!tags || tags.length === 0) {
    return true;
  }
  const problemTags = (problem.tags || []).map((t) => t.toLowerCase());
  return tags.some((tag) => problemTags.includes(tag));
}

/**
 * Deduplicate and case-insensitively sort an array of strings.
 * @param {Array<string>} arr
 * @returns {Array<string>}
 */
function dedupeAndSortCaseInsensitive(arr) {
  const lowered = new Map();
  arr.forEach((item) => {
    const lower = item.toLowerCase();
    if (!lowered.has(lower)) {
      lowered.set(lower, item);
    }
  });
  return Array.from(lowered.values()).sort((a, b) => a.toLowerCase().localeCompare(b.toLowerCase()));
}

